UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('f807142f-d685-4c91-83e5-22dfa995ea39'::uuid, 'Le traitement peut réduire l''énergie cellulaire cardiaque, la Coenzyme Q10 optimise la production d''énergie du cœur.'),('f6caf938-3b14-4ea1-9651-79378e3469de'::uuid, 'Il est crucial de surveiller la tension artérielle, ce tensiomètre permet une mesure précise à domicile.'),('6104825d-52da-4037-95b0-9ddf15175c7c'::uuid, 'Les bisphosphonates nécessitent un bon métabolisme osseux, la vitamine D3 optimise l''absorption du calcium pour des os solides.'),('610cc33c-1763-4d92-b0f9-55ea63e376fe'::uuid, 'Les bisphosphonates peuvent influencer la densité osseuse, le Magnésium contribue à la minéralisation et à la solidité des os.'),('4f43ac79-af37-464c-b6cf-18b58854e5d7'::uuid, 'Les bisphosphonates peuvent perturber la flore digestive, les probiotiques contribuent à l''équilibre de l''écosystème intestinal.'),('c752366f-6a9b-4a43-be98-4e28dfb27b55'::uuid, 'Une supplémentation en vitamine D est essentielle pour l''absorption du calcium, la vitamine D3 soutient la santé osseuse.'),('8ffecd15-cbf3-4385-8cef-7e9c53a06538'::uuid, 'L''association de traitements peut impacter le statut minéral, le Magnésium B6 aide à maintenir l''équilibre électrolytique.'),('8cd49989-ddd6-4666-888b-b34ffa807d61'::uuid, 'Certains traitements peuvent fragiliser la flore intestinale, les probiotiques maintiennent l''équilibre de l''écosystème digestif.'),('72cbe502-2df5-4703-9a7c-92b66dd0a13d'::uuid, 'Les bronchodilatateurs peuvent assécher les muqueuses nasales, le spray hypertonique aide à hydrater et décongestionner.'),('8d99b024-4215-4d6d-9ff2-9e6c840e1df8'::uuid, 'L''irritation de la gorge est fréquente avec les traitements inhalés, les pastilles apaisent la muqueuse oropharyngée.'),('50ab62e8-40cb-422e-a141-2d63f6296844'::uuid, 'Les affections respiratoires entraînent une congestion bronchique, l''huile essentielle d''eucalyptus facilite le désencombrement des voies.'),('b7c8b775-810f-4ca4-b700-027e7192721e'::uuid, 'Les bronchodilatateurs peuvent assécher les muqueuses nasales, le spray hypertonique aide à hydrater et décongestionner.'),('cdf1a1f0-f0fe-4d55-a2b4-0a4abda5ff2a'::uuid, 'L''irritation de la gorge est fréquente avec les traitements inhalés, les pastilles apaisent la muqueuse oropharyngée.'),('39085eec-307a-48a2-99d5-ce1050756eff'::uuid, 'Les affections respiratoires entraînent une congestion bronchique, l''huile essentielle d''eucalyptus facilite le désencombrement des voies.'),('7822df85-e5b0-45b1-a83c-9c945f52f38a'::uuid, 'Le calcium est essentiel à la santé osseuse, la vitamine D3 optimise son absorption et sa fixation.'),('6f5c9f67-380f-4e1f-a655-a8c82c2b5cf9'::uuid, 'Le calcium est essentiel à la santé osseuse, la vitamine D3 optimise son absorption et sa fixation.'),('b5139957-65de-4321-87e0-b1ba944cdebf'::uuid, 'Le calcium est essentiel à la santé osseuse, la vitamine D3 optimise son absorption et sa fixation.'),('40706382-2554-4f0f-8dc7-ebaa27da5d8f'::uuid, 'Les céphalosporines peuvent déséquilibrer la flore intestinale, les probiotiques rétablissent l''équilibre de la muqueuse digestive.'),('f58b9302-1e3b-4472-b24d-809f52e680d4'::uuid, 'Les céphalosporines peuvent déséquilibrer la flore intestinale, les probiotiques rétablissent l''équilibre de la muqueuse digestive.'),('8ff8a41d-fb33-4f0c-b6dc-d70b4d29ce18'::uuid, 'Les céphalosporines peuvent déséquilibrer la flore intestinale, les probiotiques rétablissent l''équilibre de la muqueuse digestive.'),('de383397-9201-4b70-a9f7-766f45234fef'::uuid, 'Les céphalosporines C3G peuvent perturber la flore intestinale, les probiotiques Lactibiane aident à restaurer l''équilibre de la muqueuse.'),('9c2690f2-b699-4929-a58f-98ba0ae4956d'::uuid, 'Les céphalosporines peuvent affaiblir le système immunitaire, la vitamine C aide à renforcer les défenses naturelles.'),('116c235f-9447-4bc4-9ebe-6b0cdade7a77'::uuid, 'Le traitement aux antibiotiques peut sensibiliser la gorge, le spray aide à apaiser l''irritation en agissant sur la muqueuse.'),('15961239-37d6-4e44-8f9a-1320b2e63310'::uuid, 'Certains contraceptifs peuvent influencer le métabolisme osseux, la vitamine D3 aide à maintenir une ossature saine.'),('f365e1fd-29c1-412e-8f52-25e6f650ed5f'::uuid, 'Certains contraceptifs peuvent influencer le métabolisme osseux, la vitamine D3 aide à maintenir une ossature saine.'),('2cd8bcde-4839-4db5-9496-1f6ceaeac9ef'::uuid, 'Certains contraceptifs peuvent influencer le métabolisme osseux, la vitamine D3 aide à maintenir une ossature saine.'),('d8f26d9c-e80c-44bb-8081-120ff2a6f3b8'::uuid, 'Les contraceptifs progestatifs peuvent avoir un impact sur l''os, la vitamine D3 aide à préserver la densité osseuse.'),('9df4a7c4-7a07-40d0-b4b6-7ddb64be4ae0'::uuid, 'Les contraceptifs progestatifs peuvent parfois entraîner un déséquilibre nerveux, le magnésium B6 aide à réguler le système nerveux.'),('726a869a-5d56-4a66-a42e-65f950e7adee'::uuid, 'Les traitements hormonaux peuvent perturber la flore digestive, les probiotiques aident à équilibrer l''écosystème intestinal.'),('f2416783-a004-45d5-bafe-9abc835b5340'::uuid, 'Les corticoïdes cutanés peuvent assécher la peau, la crème émolliente aide à restaurer la barrière cutanée.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;